mapper.select:
SELECT
	*
FROM
	CMS_ADDRESS_BOOK_GROUP
WHERE
	homepage_id = #{memberInfo.homepage_id}
AND	member_id = #{memberInfo.member_id}
AND	address_book_idx = #{address_book_idx}

mapper.update:
UPDATE
	CMS_ADDRESS_BOOK_GROUP
SET
	address_book_name = #{address_book_name}, 
	modify_date = SYSDATE
WHERE
	homepage_id = #{memberInfo.homepage_id} 
AND	member_id = #{memberInfo.member_id} 
AND	address_book_idx = #{address_book_idx}

mapper.delete:
DELETE
	CMS_ADDRESS_BOOK_GROUP
WHERE
	homepage_id = #{memberInfo.homepage_id} 
AND	member_id = #{memberInfo.member_id} 
AND	address_book_idx = #{address_book_idx}

mapper.select:
SELECT
	COUNT(*)
FROM
	CMS_ADDRESS_BOOK_GROUP
WHERE
	member_id = #{memberInfo.member_id}
AND	parent_address_book_idx = #{address_book_idx}
AND	homepage_id = #{memberInfo.homepage_id}

mapper.update:
UPDATE
	CMS_ADDRESS_BOOK
SET
	address_name = #{address_name},
	address_cell_phone = #{address_cell_phone},
	address_email = #{address_email}
WHERE
	member_id = #{memberInfo.member_id}
AND	address_book_idx = #{address_book_idx}
AND	address_idx = #{address_idx}
AND	homepage_id = #{memberInfo.homepage_id}

